var RssDiscoverFeedSchema = external_exports.object({
  url: external_exports.string().max(2048),
  title: external_exports.string().max(200),
  description: external_exports.string().max(1e3).optional(),
  // Coerce any frequency string the model returns into our three allowed values
  estimated_frequency: external_exports.string().optional().transform((v) => {
    if (!v)
      return void 0;
    const lc = v.toLowerCase();
    if (lc.includes("day") || lc.includes("hour"))
      return "daily";
    if (lc.includes("week"))
      return "weekly";
    return "irregular";
  }).optional(),
  example_titles: external_exports.array(external_exports.string().max(300)).max(10).optional()
});
