// ../api/src/routes/ai-test.ts
var aiTestRoutes = async (fastify) => {
  fastify.post("/ai/test", async (request, reply) => {
    try {
      const prompt = getPrompt("diagnostic", 1);
      const messages = interpolatePrompt(prompt, {});
      const startTime = Date.now();
      const response = await createChatCompletion(
        {
          model: "anthropic/claude-3-haiku",
          // Fast, cheap model for testing
          messages: [
            { role: "system", content: messages.system },
            { role: "user", content: messages.user }
          ],
          temperature: prompt.metadata.temperature,
          max_tokens: prompt.metadata.max_tokens
        },
        5e3
        // 5 second timeout for diagnostic
      );
      const duration = Date.now() - startTime;
      const responseText = response.choices[0]?.message.content || "";
      return reply.status(200).send({
        success: true,
        model: response.model,
        response: responseText,
        usage: response.usage,
        duration_ms: duration,
        message: "OpenRouter API connection successful"
      });
    } catch (error) {
      const err = error;
      return reply.status(500).send({
        success: false,
        error: err.name,
        message: err.message
      });
    }
  });
};

