// ../api/src/routes/search.ts
init_dist2();
var logger7 = createLogger({ name: "search" });
async function searchRoute(fastify) {
  fastify.get(
    "/pots/:potId/search",
    async (request) => {
      const requestId = request.id;
      const potId = request.params.potId;
      let query;
      try {
        query = SearchQuerySchema.parse(request.query);
      } catch (error) {
        return {
          ok: false,
          error: "Invalid search query",
          details: error.message
        };
      }
      const { q, limit, offset, type, min_confidence, has_assets } = query;
      logger7.info(
        {
          requestId,
          pot_id: potId,
          q: q.substring(0, 50),
          limit,
          offset,
          type,
          has_assets
        },
        "Search requested"
      );
      const { results, intelligence_results, total } = await searchEntries({
        potId,
        query: q,
        limit,
        offset,
        type,
        minConfidence: min_confidence,
        hasAssets: has_assets
      });
      logger7.info(
        {
          requestId,
          pot_id: potId,
          total,
          returned: results.length
        },
        "Search completed"
      );
      return {
        q,
        pot_id: potId,
        results,
        intelligence_results,
        total,
        limit,
        offset
      };
    }
  );
}

